try:
    L = int(input("Enter Likelihood (1-3): "))
    I = int(input("Enter Impact (1-3): "))

    if L not in (1, 2, 3) or I not in (1, 2, 3):
        print("Invalid input")
    else:
        score = L * I
        if score <= 2:
            priority = "Low"
            action = "Monitor"
        elif score <= 4:
            priority = "Medium"
            action = "Fix Soon"
        else:
            priority = "High"
            action = "Fix Now"

        print(f"Risk Score = {score} | Priority = {priority} | Action = {action}")

except ValueError:
    print("Invalid input (please enter integers only)")

import hashlib
def sha256_file(path: str) -> str:
    sha = hashlib.sha256()
    with open(path, "rb") as f:
        while True:
            chunk = f.read(4096)
            if not chunk:
                break
            sha.update(chunk)
    return sha.hexdigest()

file_path = input("Enter file path: ").strip()
print("SHA-256:", sha256_file(file_path))
